mapper.select:
SELECT d.id, d.id_site, d.devicename, d.datatablename, IFNULL(d.meter_type, 0) AS meter_type, d.id_device_type, d.serialnumber
FROM device AS d
WHERE d.is_delete = 0 AND d.`status` = 1 AND d.id_site = #{id_site} GROUP BY d.id;

SELECT ( SELECT ROUND(IFNULL(SUM(v.nvmActiveEnergy), 0), 1) AS current_month FROM (
SELECT DATE_FORMAT(dv.time, '%Y-%m' ) AS time_format, DATE_FORMAT( dv.time, '%Y-%m' ) AS time_full, IFNULL(SUM(dv.ActualGeneration), 0) AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(#{start_date},"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(#{end_date},"%Y-%m-%d 23:59:59" )
)v ) AS current_month,
( SELECT ROUND(IFNULL(SUM(v.nvmActiveEnergy), 0), 1) AS compare_current_month FROM (
SELECT DATE_FORMAT(dv.time, '%Y-%m' ) AS time_format, DATE_FORMAT( dv.time, '%Y-%m' ) AS time_full, IFNULL(SUM(dv.ActualGeneration), 0) AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL-1 MONTH),"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(DATE_ADD(#{end_date},INTERVAL-1 MONTH),"%Y-%m-%d 23:59:59" )
)v ) AS compare_current_month,
( SELECT ROUND(IFNULL(SUM(v.year_over_year), 0), 1) AS year_over_year FROM (
SELECT IFNULL(SUM(dv.ActualGeneration), 0) AS year_over_year FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND dv.time BETWEEN DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 YEAR),"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT( DATE_ADD(#{end_date},INTERVAL -1 YEAR) ,"%Y-%m-%d 23:59:59" )
)v ) AS year_over_year,
DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 YEAR),"%M %Y" ) AS year_over_date

SELECT m.time_full, m.time_format, m.categories_time, m.days, ROUND(m.nvmActiveEnergy, 2) AS `energy` FROM(
SELECT t.time_full, t.time_format, t.categories_time, t.days, IFNULL(SUM(t.nvmActiveEnergy), 0) AS nvmActiveEnergy FROM (
SELECT DATE_FORMAT(#{itemTime.start_date}, '%b %Y') AS categories_time, DATE_FORMAT(#{itemTime.start_date}, '%Y-%m' ) AS time_format, DATE_FORMAT( #{itemTime.start_date}, '%Y-%m') AS time_full, DATE_FORMAT( LAST_DAY(#{itemTime.start_date}), '%d' ) AS days,
IFNULL(SUM(dv.ActualGeneration), 0) AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(#{itemTime.start_date},"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(#{itemTime.end_date},"%Y-%m-%d 23:59:59" )
)t
) m ORDER BY m.time_full ASC

SELECT t.peak_demand_date, MAX(t.peak_demand) AS peak_demand FROM (
SELECT DATE_FORMAT( CONVERT_TZ( dv.time, 'UTC', t.`value` ), '%b %d, %Y at %H:%i %p' ) AS peak_demand_date, dv.nvmActivePower AS peak_demand FROM ${item.datatablename} dv LEFT JOIN device d ON d.id = dv.id_device LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone WHERE DATE_FORMAT(CONVERT_TZ( dv.time, "UTC", t.`value`), "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(#{start_date},"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT( #{end_date},"%Y-%m-%d 00:00:00" ) ORDER BY dv.nvmActivePower DESC LIMIT 1
)t

SELECT t.peak_flow_rate_date, MAX(t.peak_flow_rate) AS peak_flow_rate FROM (
SELECT DATE_FORMAT( CONVERT_TZ( dv.time, 'UTC', t.`value` ), 'at %H:%i %p on %b %d, %Y' ) AS peak_flow_rate_date, dv.nvmActivePower AS peak_flow_rate FROM ${item.datatablename} dv LEFT JOIN device d ON d.id = dv.id_device LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone WHERE DATE_FORMAT(CONVERT_TZ( dv.time, "UTC", t.`value`), "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(#{start_date},"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT( #{end_date},"%Y-%m-%d 00:00:00" ) ORDER BY dv.nvmActivePower DESC LIMIT 1
)t

SELECT SUM(v.nvmActiveEnergy) AS lastMonth FROM (
SELECT DATE_FORMAT(dv.time, '%b %d' ) AS categories_time, DATE_FORMAT(dv.time, '%Y-%m-%d' ) AS time_format, DATE_FORMAT( dv.time, '%b %d, %Y' ) AS time_full, dv.ActualGeneration AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 MONTH),"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(DATE_ADD(#{end_date},INTERVAL -1 MONTH),"%Y-%m-%d 23:59:59" )
)v

SELECT t.categories_time, t.time_full AS max_annual_daily_date, t.time_format, SUM(t.nvmActiveEnergy) AS max_annual_daily,
( SELECT SUM(v.nvmActiveEnergy) AS last_year FROM (
SELECT DATE_FORMAT(dv.time, '%b %d' ) AS categories_time, DATE_FORMAT(dv.time, '%Y-%m-%d' ) AS time_format, DATE_FORMAT( dv.time, '%b %d, %Y' ) AS time_full, dv.ActualGeneration AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 YEAR),"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(DATE_ADD(#{end_date},INTERVAL -1 YEAR),"%Y-%m-%d 23:59:59" )
)v ) AS last_year,
( SELECT AVG(nvmActiveEnergy) AS avg_last_eriod FROM ( SELECT SUM(t.nvmActiveEnergy) AS nvmActiveEnergy FROM(
SELECT DATE_FORMAT(dv.time, '%b %d' ) AS categories_time, DATE_FORMAT(dv.time, '%Y-%m-%d' ) AS time_format, DATE_FORMAT( dv.time, '%b %d, %Y' ) AS time_full, dv.ActualGeneration AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 MONTH),"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 MONTH),"%Y-%m-%d 23:59:59" )
)t GROUP BY t.time_format )v ) AS avg_last_eriod
FROM(
SELECT DATE_FORMAT(dv.time, '%b %d' ) AS categories_time, DATE_FORMAT(dv.time, '%Y-%m-%d' ) AS time_format, DATE_FORMAT( dv.time, '%b %d, %Y' ) AS time_full, dv.ActualGeneration AS nvmActiveEnergy FROM ${table_data_report} dv WHERE dv.id_device = #{item.id} AND DATE_FORMAT(dv.time, "%Y-%m-%d %H:%i:%s" ) BETWEEN DATE_FORMAT(DATE_ADD(#{start_date},INTERVAL -1 YEAR),"%Y-%m-%d 00:00:00" ) AND DATE_FORMAT(DATE_ADD(#{end_date},INTERVAL -1 MONTH),"%Y-%m-%d 23:59:59" )
)t GROUP BY t.time_format ORDER BY t.nvmActiveEnergy DESC LIMIT 1
